import type { PanelConstraints } from "../../components/panel/types";
import { compareLayoutNumbers } from "./compareLayoutNumbers";
import { formatLayoutNumber } from "./formatLayoutNumber";

// Panel size must be in percentages; pixel values should be pre-converted
export function validatePanelSize({
  overrideDisabledPanels,
  panelConstraints,
  prevSize,
  size
}: {
  overrideDisabledPanels?: boolean;
  panelConstraints: PanelConstraints;
  prevSize: number;
  size: number;
}) {
  const {
    collapsedSize = 0,
    collapsible,
    disabled,
    maxSize = 100,
    minSize = 0
  } = panelConstraints;

  if (disabled && !overrideDisabledPanels) {
    return prevSize;
  }

  if (compareLayoutNumbers(size, minSize) < 0) {
    if (collapsible) {
      // Collapsible panels should snap closed or open only once they cross the halfway point between collapsed and min size.
      const halfwayPoint = (collapsedSize + minSize) / 2;
      if (compareLayoutNumbers(size, halfwayPoint) < 0) {
        size = collapsedSize;
      } else {
        size = minSize;
      }
    } else {
      size = minSize;
    }
  }

  size = Math.min(maxSize, size);
  size = formatLayoutNumber(size);

  return size;
}

import memoize from 'memoize-one';
import {
  defaultComponents,
  SelectComponentsGeneric,
} from '../components/index';
import { default as AnimatedInput } from './Input';
import { default as AnimatedMultiValue } from './MultiValue';
import { default as AnimatedPlaceholder } from './Placeholder';
import { default as AnimatedSingleValue } from './SingleValue';
import { default as AnimatedValueContainer } from './ValueContainer';

const makeAnimated = (
  externalComponents: Partial<SelectComponentsGeneric> = {}
): Partial<SelectComponentsGeneric> => {
  const components = defaultComponents({ components: externalComponents });
  const {
    Input,
    MultiValue,
    Placeholder,
    SingleValue,
    ValueContainer,
    ...rest
  } = components;
  return {
    Input: AnimatedInput(Input),
    MultiValue: AnimatedMultiValue(MultiValue),
    Placeholder: AnimatedPlaceholder(Placeholder),
    SingleValue: AnimatedSingleValue(SingleValue),
    ValueContainer: AnimatedValueContainer(ValueContainer),
    ...rest,
  };
};

const AnimatedComponents = makeAnimated();

export const Input = AnimatedComponents.Input;
export const MultiValue = AnimatedComponents.MultiValue;
export const Placeholder = AnimatedComponents.Placeholder;
export const SingleValue = AnimatedComponents.SingleValue;
export const ValueContainer = AnimatedComponents.ValueContainer;

export default memoize(makeAnimated);

